from flask import Flask, request, session, redirect, url_for
import xml.etree.ElementTree as ET

app = Flask(__name__)
app.secret_key = 'your_secret_key'

@app.route('/saml/callback', methods=['POST'])
def saml_callback():
    if 'SAMLResponse' not in request.form:
        return "SAML assertion is missing", 400
    
    saml_response = request.form['SAMLResponse']
    
    # Parse the SAML response
    root = ET.fromstring(saml_response)
    
    # Extract user attributes from the Assertion elements
    name_id = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Subject/{urn:oasis:names:tc:SAML:2.0:assertion}NameID').text
    
    # Create a user session
    session['user'] = {'name_id': name_id}
    
    return redirect(url_for('home'))

@app.route('/')
def home():
    if 'user' in session:
        return f"Hello, {session['user']['name_id']}!"
    else:
        return "User is not logged in", 403

if __name__ == '__main__':
    app.run(debug=True)